import{_ as a,o as t,c as b,j as r,a as p,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"沙沙果实","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/2.改造与功法/改造/6.一次性改造/沙沙果实.md","filePath":"4.资源分区/2.改造与功法/改造/6.一次性改造/沙沙果实.md"}'),n={name:"4.资源分区/2.改造与功法/改造/6.一次性改造/沙沙果实.md"};function o(d,e,l,_,i,c){return t(),b("div",null,[...e[0]||(e[0]=[r("h1",{id:"沙沙果实",tabindex:"-1"},[p("沙沙果实 "),r("a",{class:"header-anchor",href:"#沙沙果实","aria-label":'Permalink to "沙沙果实"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：绯红庆典040")])])],-1),s('<h1 id="沙沙果实-1" tabindex="-1">沙沙果实 <a class="header-anchor" href="#沙沙果实-1" aria-label="Permalink to &quot;沙沙果实&quot;">​</a></h1><p>名称：恶魔果实-沙沙果实<br> 类型：一次性改造（4A24 ）<br> 本质：特异<br> 分类：自然系恶魔果实<br> 价格：A+4800<br> 描述：源自海贼王世界的恶魔果实之一的沙沙果实，原作属于沙鳄鱼克洛克达尔所有。能将身体化为沙子的自然系果实。<br> 沙化身躯：和一般的元素化不同，沙沙果实的元素化是将身体化为沙子，这让沙沙果实能力者免疫所有单体物理伤害和A级及以下单体负面效果并且免疫坠落伤害 ，这视为一种超微型集群。但因为是沙子，所以本特性会因为任意等级的潮湿特性而失效。（ps落地水会把这个人坑死）<br> 恶魔果实：恶魔果实能力者被海洋唾弃，在海水中你的游泳检定必定失败并且无法在海水下憋气，即使你具有无需呼吸或免疫环境的能力。<br> 沙子掌控：用某个世界的话来说，你拥有操控沙子的能力。你获得一种新建攻击方式，绑定一把已有近战武器将其融入身体，而后可以以【操控+专注+专注：沙子掌控+学识：自然学+武器伤害】将身体变为对应武器进行攻击，攻击时触及范围改为敏感范围且附带融入武器的全部特性。你可以操控沙子形成屏障进行格挡，以【专注+专注：沙子掌控】代替进行格挡。对于沙子的掌握也给你带来的对气象的一部分认识，现在你可以通过观测天象，得知近5天的天气走向。</p><p>下属技巧<br> 果实开发——沙之盾<br> 价格：B+2000<br> 动作：自由动作<br> 描述：周身的每一次沙子都被你掌控，会自动应对攻击。<br> 效果：每轮一次，自由动作/反射动作启动，你身边的沙子会自动组成护盾进行格挡，并且本次格挡额外获得5点掩蔽防御。这个效果只需要每轮一个自由动作维持。</p><p>果实开发——沙之铠<br> 价格：B+2000<br> 动作：移动动作<br> 描述：你的身体就是沙子然后在表皮中对沙子进行了二次构造使其构成一层可以自我再生的外皮。<br> 效果：移动动作消耗2意志力开启，每轮获得5点临时生命（不可叠加）同时获得4点天生防御和基于天防的【超级坚韧】特性，持续一场景。</p><p>果实开发——精细掌控<br> 价格：C+1000<br> 描述：既然身体全部由沙子构成，那如果我精细的掌控了我身体每一粒沙子，是不是可以随意进入缝隙。。。<br> 效果：基于对沙沙果实的完全开发，你掌握了身体的每一粒沙子，你的行动不再是肌肉牵动而是操控身体每一处沙子而行动，你获得C级免疫肢体妨碍点数带来的减值和严重状态的效果。并且你可以化为沙粒入侵其他空间，只要有一丝缝隙存在你就可以顺着进入其中，这是一种C级变形来源传送移动效果。</p><p>果实开发——精髓·干涸<br> 价格：C+1000<br> 描述：沙漠的精髓在于干涸，这对生物也是致命的。你可以从敌人身体中夺走他的水分，使其越发衰弱。<br> 效果：现在被你击中的目标想要以强韧检定对抗伤害出目，失败则陷入C级环境来源的衰老效果，特殊的，该衰老效果在脱离战斗后可以靠补充等体积水分恢复。对于沙漠果实精髓的掌握，让你对沙沙果实的使用越发得心应手，你的专注检定获得9加骰。<br> 差价提升至B+2000<br> 效果：现在被你击中的目标想要以强韧检定对抗伤害出目，失败则其攻击检定获得状态并且陷入B级环境来源的衰老效果，特殊的，该衰老效果在脱离战斗后可以靠补充等体积水分恢复。沙沙果实的觉醒正在向你招手，你专注检定加骰提升为8加骰。</p><p>果实开发——沙漠宝刀<br> 价格：C+1000<br> 动作：标准动作<br> 描述：把手臂变成沙刃后巨大化放出，通过强化高频震动，赋予了沙子刀刃般的切割能力，有把地面斩开的锋利度。<br> 效果：进行一次攻击，本次攻击转为对触及范围内全部敌人进行攻击，敌方以反射豁免对抗。本次攻击带有【破甲5】，本次攻击破甲结算后仍有剩余则转化为攻击上的增强加值，至多5点。</p><p>果实开发——沙岚<br> 价格：C+1000<br> 描述：沙尘风暴！！<br> 效果：以整轮动作进行冲锋攻击，本次攻击会攻击移动路径上触及范围内的所有敌方单位并将他们全部卷入沙岚之中，这视为一次C级环境来源的击飞效果，敌方以强韧豁免对抗。本次击飞效果结束后计算坠落伤害的距离时，按照60米计算。</p><p>果实开发——沙岚·重<br> 价格：B+2000（可由沙岚差价升级）<br> 效果：以整轮动作进行冲锋攻击，本次攻击不会使你的基础防御承受减值同时会攻击移动路径上触及范围内的所有敌方单位并将他们重重击倒后再将其卷入风暴，这次攻击具有【碾压】特性，并视为一次B级环境来源的击飞效果，敌方以强韧豁免对抗。计算坠落伤害时按60米计算。这次冲锋攻击即使对方离开了攻击范围，也可以按照正常脱离攻击范围一般进行冲锋攻击。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',11)])])}const m=a(n,[["render",o]]);export{f as __pageData,m as default};
